const SB_URL = $('Config').first().json.SUPABASE_URL;
const SB_KEY = $('Config').first().json.SUPABASE_SERVICE_KEY;
const hdrs = {
  'apikey': SB_KEY,
  'Authorization': 'Bearer ' + SB_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

async function sbGet(path) {
  const res = await fetch(SB_URL + '/rest/v1/' + path, {
    headers: { apikey: SB_KEY, Authorization: 'Bearer ' + SB_KEY }
  });
  if (!res.ok) return [];
  return res.json();
}

async function sbPost(path, body) {
  const res = await fetch(SB_URL + '/rest/v1/' + path, {
    method: 'POST', headers: hdrs, body: JSON.stringify(body)
  });
  return res.ok;
}

async function sbRpc(fn, params) {
  const res = await fetch(SB_URL + '/rest/v1/rpc/' + fn, {
    method: 'POST',
    headers: { apikey: SB_KEY, Authorization: 'Bearer ' + SB_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify(params)
  });
  return res.ok;
}

// ── Helpers ──
function todayStr() { return new Date().toISOString().slice(0, 10); }
function daysAgo(n) { const d = new Date(); d.setDate(d.getDate() - n); return d.toISOString(); }
function billingPeriod() { const d = new Date(); return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0'); }

function getOrgHour(tz) {
  try {
    const f = new Intl.DateTimeFormat('en-US', { hour: 'numeric', hour12: false, timeZone: tz });
    return parseInt(f.format(new Date()), 10);
  } catch { return new Date().getUTCHours() + 3; } // fallback TR
}

function parseHour(timeStr) {
  return parseInt((timeStr || '09:00').split(':')[0], 10);
}

// ── 1. Aktif reactivation_chat workflow'ları ──
const workflows = await sbGet(
  'org_workflows?template_id=eq.reactivation_chat&is_active=eq.true' +
  '&select=id,organization_id,config'
);

if (!workflows.length) {
  return [{ json: { processed: 0, message: 'No active reactivation workflows' } }];
}

const results = [];

for (const wf of workflows) {
  const orgId = wf.organization_id;
  const cfg = wf.config || {};
  const inactiveDays   = Math.max(cfg.inactive_days || 30, 30); // minimum 30
  const cooldownDays   = cfg.cooldown_days || 30;
  const dailyLimit     = cfg.daily_limit || 50;
  const timezone       = cfg.timezone || 'Europe/Istanbul';
  const whStart        = parseHour(cfg.working_hours_start || '09:00');
  const whEnd          = parseHour(cfg.working_hours_end || '17:00');
  const targetStatuses = (cfg.target_statuses || 'lost,new,in_progress').split(',');
  const templateName   = cfg.message_template || '';

  // ── Working hours check (org timezone) ──
  const orgHour = getOrgHour(timezone);
  if (orgHour < whStart || orgHour >= whEnd) {
    results.push({ org: orgId, status: 'skip', reason: 'outside_working_hours', orgHour, window: whStart + '-' + whEnd });
    continue;
  }

  if (!templateName) {
    results.push({ org: orgId, status: 'skip', reason: 'no_template' });
    continue;
  }

  // ── Batch size: dengeli dağılım ──
  // Çalışma saatleri içindeki kalan pencere sayısına göre batch hesapla
  const windowsLeft = Math.max(1, (whEnd - orgHour) * 2); // her saat 2 pencere (30dk)
  const batchSize = Math.max(1, Math.ceil(dailyLimit / ((whEnd - whStart) * 2)));

  // ── 2. Quota check ──
  const period = billingPeriod();
  const usage = await sbGet(
    'usage_counters?organization_id=eq.' + orgId +
    '&metric=eq.reactivation_lead_count&billing_period=eq.' + period +
    '&select=value&limit=1'
  );
  const usedCount = (usage[0] && usage[0].value) || 0;

  const subRows = await sbGet(
    'org_subscriptions?organization_id=eq.' + orgId + '&select=plan_id&limit=1'
  );
  const planId = (subRows[0] && subRows[0].plan_id) || 'legacy';

  let effectiveLimit = 999999;
  if (planId !== 'legacy') {
    const entRows = await sbGet(
      'plan_entitlements?plan_id=eq.' + planId +
      '&feature_key=eq.workflow_reactivation&select=limit_value&limit=1'
    );
    const planLimit = (entRows[0] && entRows[0].limit_value) || 0;
    const overrideRows = await sbGet(
      'org_entitlement_overrides?organization_id=eq.' + orgId +
      '&feature_key=eq.workflow_reactivation&select=limit_override&limit=1'
    );
    effectiveLimit = (overrideRows[0] && overrideRows[0].limit_override) || planLimit;
  }

  if (usedCount >= effectiveLimit) {
    results.push({ org: orgId, status: 'skip', reason: 'quota_exceeded', used: usedCount, limit: effectiveLimit });
    continue;
  }

  // ── 3. Daily limit check ──
  const todayRuns = await sbGet(
    'workflow_runs?org_workflow_id=eq.' + wf.id +
    '&status=eq.success&created_at=gte.' + todayStr() + 'T00:00:00Z' +
    '&select=id&limit=' + (dailyLimit + 1)
  );

  if (todayRuns.length >= dailyLimit) {
    results.push({ org: orgId, status: 'skip', reason: 'daily_limit', sent_today: todayRuns.length });
    continue;
  }

  const remaining = Math.min(batchSize, dailyLimit - todayRuns.length, effectiveLimit - usedCount);
  if (remaining <= 0) {
    results.push({ org: orgId, status: 'skip', reason: 'no_remaining' });
    continue;
  }

  // ── 4. WA credentials check ──
  const orgRows = await sbGet(
    'organizations?id=eq.' + orgId + '&select=channel_config,ai_persona&limit=1'
  );
  const orgConfig = (orgRows[0] && orgRows[0].channel_config) || {};
  const waConfig = orgConfig.whatsapp || {};
  const phoneNumberId = waConfig.phone_number_id;
  const accessToken = waConfig.access_token;

  const orgLang = (orgRows[0] && orgRows[0].ai_persona && orgRows[0].ai_persona.language) || 'tr';
  const LANG_MAP = { en: 'en_US', de: 'de', tr: 'tr', ar: 'ar', fr: 'fr_FR' };
  const templateLangCode = LANG_MAP[orgLang] || orgLang;

  if (!phoneNumberId || !accessToken) {
    results.push({ org: orgId, status: 'skip', reason: 'no_wa_credentials' });
    continue;
  }

  // ── 5a. Hareketsiz lead'ler (inactive_days geçmiş) ──
  const cutoff = daysAgo(inactiveDays);
  const statusFilter = targetStatuses.map(s => s.trim()).join(',');
  const inactiveLeads = await sbGet(
    'leads?organization_id=eq.' + orgId +
    '&status=in.(' + statusFilter + ')' +
    '&updated_at=lte.' + cutoff +
    '&select=id,contact_id' +
    '&order=updated_at.asc' +
    '&limit=' + (remaining * 3)
  );

  // ── 5b. Cold lead'ler (hiç konuşması yok — CRM/CSV import) ──
  const coldCandidates = await sbGet(
    'leads?organization_id=eq.' + orgId +
    '&status=in.(' + statusFilter + ')' +
    '&select=id,contact_id' +
    '&order=created_at.asc' +
    '&limit=' + (remaining * 3)
  );

  // Cold lead filtresi: hiç conversation'ı olmayan contact'lar
  let coldLeads = [];
  if (coldCandidates.length) {
    const coldContactIds = [...new Set(coldCandidates.map(l => l.contact_id).filter(Boolean))];
    if (coldContactIds.length) {
      const existingConvos = await sbGet(
        'conversations?organization_id=eq.' + orgId +
        '&contact_id=in.(' + coldContactIds.join(',') + ')' +
        '&select=contact_id'
      );
      const hasConvo = new Set(existingConvos.map(c => c.contact_id));
      coldLeads = coldCandidates.filter(l => l.contact_id && !hasConvo.has(l.contact_id));
    }
  }

  // ── 5c. Merge + dedup (inactive + cold) ──
  const seen = new Set();
  const allLeads = [];
  for (const l of [...inactiveLeads, ...coldLeads]) {
    if (l.contact_id && !seen.has(l.contact_id)) {
      seen.add(l.contact_id);
      allLeads.push(l);
    }
  }

  if (!allLeads.length) {
    results.push({ org: orgId, status: 'skip', reason: 'no_eligible_leads' });
    continue;
  }

  // ── 6. Dedup: cooldown check ──
  const allContactIds = allLeads.map(l => l.contact_id);
  const cooldownCutoff = daysAgo(cooldownDays);
  const recentRuns = await sbGet(
    'workflow_runs?org_workflow_id=eq.' + wf.id +
    '&contact_id=in.(' + allContactIds.join(',') + ')' +
    '&status=eq.success' +
    '&created_at=gte.' + cooldownCutoff +
    '&select=contact_id'
  );
  const recentContactIds = new Set(recentRuns.map(r => r.contact_id));
  const eligibleLeads = allLeads.filter(l => !recentContactIds.has(l.contact_id)).slice(0, remaining);

  if (!eligibleLeads.length) {
    results.push({ org: orgId, status: 'skip', reason: 'all_in_cooldown' });
    continue;
  }

  // ── 7. Contact phone'ları ──
  const batchContactIds = eligibleLeads.map(l => l.contact_id);
  const contacts = await sbGet(
    'contacts?id=in.(' + batchContactIds.join(',') + ')&select=id,phone,full_name'
  );
  const contactMap = {};
  for (const c of contacts) contactMap[c.id] = c;

  // ── 8. Template gönder ──
  let sent = 0, failed = 0;

  for (const lead of eligibleLeads) {
    const contact = contactMap[lead.contact_id];
    if (!contact || !contact.phone) { failed++; continue; }

    const phone = contact.phone.replace(/^\+/, '');

    try {
      const waRes = await fetch(
        'https://graph.facebook.com/v21.0/' + phoneNumberId + '/messages',
        {
          method: 'POST',
          headers: { 'Authorization': 'Bearer ' + accessToken, 'Content-Type': 'application/json' },
          body: JSON.stringify({
            messaging_product: 'whatsapp',
            to: phone,
            type: 'template',
            template: { name: templateName, language: { code: templateLangCode } }
          })
        }
      );

      const waOk = waRes.ok;
      await sbPost('workflow_runs', {
        org_workflow_id: wf.id,
        organization_id: orgId,
        contact_id: lead.contact_id,
        lead_id: lead.id,
        status: waOk ? 'success' : 'failed',
        result: waOk
          ? { template: templateName, phone, source: seen.has(lead.contact_id) ? 'inactive' : 'cold_import' }
          : { error: 'wa_send_failed', http_status: waRes.status }
      });

      if (waOk) {
        sent++;
        await sbRpc('increment_usage', { p_organization_id: orgId, p_metric: 'reactivation_lead_count', p_amount: 1 });
      } else { failed++; }
    } catch (err) {
      failed++;
      await sbPost('workflow_runs', {
        org_workflow_id: wf.id, organization_id: orgId,
        contact_id: lead.contact_id, lead_id: lead.id,
        status: 'failed', result: { error: String(err) }
      });
    }
  }

  results.push({ org: orgId, status: 'done', sent, failed, eligible: eligibleLeads.length, batch: batchSize, cold: coldLeads.length });
}

return [{ json: { total_orgs: workflows.length, results } }];
